#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define BLOCK_SIZE 16

void random_matrix(float *I, int rows, int cols);
void runTest(int argc, char** argv);
void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1>     - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

    exit(1);
}

int
main(int argc, char** argv) 
{
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    runTest(argc, argv);

    return EXIT_SUCCESS;
}

void
runTest(int argc, char** argv) 
{
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI, varROI;
    float Jc, G2, L, num, den, qsqr;
    int *iN, *iS, *jE, *jW, k;
    float *dN, *dS, *dW, *dE;
    float cN, cS, cW, cE, D;
    float *c, *E_C, *W_C, *N_C, *S_C;
    float *temp_result;

    unsigned int r1, r2, c1, c2;

    if (argc == 9)
    {
        rows = atoi(argv[1]);  
        cols = atoi(argv[2]);  
        if ((rows%16!=0) || (cols%16!=0)){
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1   = atoi(argv[3]);  
        r2   = atoi(argv[4]);  
        c1   = atoi(argv[5]);  
        c2   = atoi(argv[6]);  
        lambda = atof(argv[7]); 
        niter = atoi(argv[8]); 

    }
    else{
        usage(argc, argv);
    }

    size_I = cols * rows;
    size_R = (r2-r1+1)*(c2-c1+1);   

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));
    c  = (float *)malloc(sizeof(float) * size_I);
    E_C = (float *)malloc(sizeof(float) * size_I);
    W_C = (float *)malloc(sizeof(float) * size_I);
    N_C = (float *)malloc(sizeof(float) * size_I);
    S_C = (float *)malloc(sizeof(float) * size_I);
    temp_result = (float *)malloc(sizeof(float) * size_I);

    iN = (int *)malloc(sizeof(int) * rows);
    iS = (int *)malloc(sizeof(int) * rows);
    jW = (int *)malloc(sizeof(int) * cols);
    jE = (int *)malloc(sizeof(int) * cols);    

    dN = (float *)malloc(sizeof(float) * size_I);
    dS = (float *)malloc(sizeof(float) * size_I);
    dW = (float *)malloc(sizeof(float) * size_I);
    dE = (float *)malloc(sizeof(float) * size_I);    

    for (int i=0; i < rows; i++) {
        iN[i] = i-1;
        iS[i] = i+1;
    }    
    for (int j=0; j < cols; j++) {
        jW[j] = j-1;
        jE[j] = j+1;
    }
    iN[0]    = 0;
    iS[rows-1] = rows-1;
    jW[0]    = 0;
    jE[cols-1] = cols-1;

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++ ) {
        J[k] = (float)exp(I[k]);
    }
    printf("Start the SRAD main loop\n");

    for (iter=0; iter < niter; iter++){     
        sum=0; sum2=0;
        for (int i=r1; i<=r2; i++) {
            for (int j=c1; j<=c2; j++) {
                tmp   = J[i * cols + j];
                sum  += tmp;
                sum2 += tmp*tmp;
            }
        }
        meanROI = sum / size_R;
        varROI  = (sum2 / size_R) - meanROI*meanROI;
        q0sqr   = varROI / (meanROI*meanROI);

        #pragma omp parallel for
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) { 

                k = i * cols + j;
                Jc = J[k];

                dN[k] = J[iN[i] * cols + j] - Jc;
                dS[k] = J[iS[i] * cols + j] - Jc;
                dW[k] = J[i * cols + jW[j]] - Jc;
                dE[k] = J[i * cols + jE[j]] - Jc;

                G2 = (dN[k]*dN[k] + dS[k]*dS[k] 
                    + dW[k]*dW[k] + dE[k]*dE[k]) / (Jc*Jc);

                L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

                num  = (0.5*G2) - ((1.0/16.0)*(L*L));
                den  = 1 + (.25*L);
                qsqr = num/(den*den);


                den = (qsqr-q0sqr) / (q0sqr * (1+q0sqr));
                c[k] = 1.0 / (1.0+den);


                if (c[k] < 0) {c[k] = 0;}
                else if (c[k] > 1) {c[k] = 1;}

                temp_result[k] = c[k];
                E_C[k] = dE[k];
                W_C[k] = dW[k];
                S_C[k] = dS[k];
                N_C[k] = dN[k];
            }
        }

        #pragma omp parallel for
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {        

                k = i * cols + j;

                cN = temp_result[k];
                cS = temp_result[iS[i] * cols + j];
                cW = temp_result[k];
                cE = temp_result[i * cols + jE[j]];

                D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

                J[k] = J[k] + 0.25*lambda*D;
            }
        }
    }

#ifdef OUTPUT

    printf("Printing Output:\n"); 
    for(int i = 0; i < rows; i++){
        for(int j = 0; j < cols; j++){
            printf("%.5f ", J[i * cols + j]); 
        }	
        printf("\n"); 
    }
#endif 

    printf("Computation Done\n");

    free(I);
    free(J);
    free(iN); free(iS); free(jW); free(jE);
    free(dN); free(dS); free(dW); free(dE);
    free(E_C); free(W_C); free(N_C); free(S_C);
    free(temp_result);
    free(c);

}

void random_matrix(float *I, int rows, int cols){

    srand(7);

    for(int i = 0; i < rows; i++){
        for(int j = 0; j < cols; j++){
            I[i * cols + j] = rand()/(float)RAND_MAX;
        }
    }

}
